  },
  {
    label: "Marketing",
    items: [
      { href: "/admin/promos", label: "Promos", icon: "Percent" },
      { href: "/admin/resenas", label: "Reseñas", icon: "Star" },
      { href: "/admin/b2b", label: "B2B", icon: "Briefcase" },
